when (queue) {
    null -> if (_queue.compareAndSet(null, task)) return true
    is Queue<*> -> {
        when ((queue as Queue<Runnable>).addLast(task)) {
            Queue.ADD_SUCCESS -> return true
            Queue.ADD_CLOSED -> return false
            Queue.ADD_FROZEN -> _queue.compareAndSet(queue, queue.next())
        }
    }
    else -> when {
        queue === CLOSED_EMPTY -> return false
        else -> {
            // update to full-blown queue to add one more
            val newQueue = Queue<Runnable>(Queue.INITIAL_CAPACITY, singleConsumer = true)
            newQueue.addLast(queue as Runnable)
            newQueue.addLast(task)
            if (_queue.compareAndSet(queue, newQueue)) return true
        }
    }
}

fun <T> getOrNull(
    clazz: KClass<*>,
    qualifier: Qualifier? = null,
    parameters: ParametersDefinition? = null,
): T? {
    return try {
        get(clazz, qualifier, parameters)
    } catch (e: ClosedScopeException) {
        _koin.logger.debug("* Scope closed - no instance found for ${clazz.getFullName()} on scope ${toString()}")
        null
    } catch (e: NoDefinitionFoundException) {
        _koin.logger.debug("* No instance found for type '${clazz.getFullName()}' on scope '${toString()}'")
        null
    } catch (e: MissingScopeValueException) {
        _koin.logger.debug("* No Scoped value found for type '${clazz.getFullName()}' on scope '${toString()}'")
        null
    }
}

override fun createStatement(): List<String> {
    @OptIn(InternalApi::class)
    val alterTablePrefix = "ALTER TABLE ${currentTransaction().identity(table)} ADD"
    val isH2withCustomPKConstraint = currentDialect is H2Dialect && isLastColumnInPK
    val isOracle = currentDialect is OracleDialect
    val columnDefinition = when {
        isPrimaryConstraintWillBeDefined && isLastColumnInPK && !isH2withCustomPKConstraint && !isOracle ->
            descriptionDdl(false) + ", ADD ${table.primaryKeyConstraint()}"

        isH2withCustomPKConstraint -> descriptionDdl(true)
        else -> descriptionDdl(false)
    }

    val addConstr = if (isH2withCustomPKConstraint || (isOracle && isPrimaryConstraintWillBeDefined)) {
        "$alterTablePrefix ${table.primaryKeyConstraint()}"
    } else {
        null
    }
    return listOfNotNull("$alterTablePrefix $columnDefinition", addConstr)
}

private fun implicitJoin(
    otherTable: ColumnSet,
    joinType: JoinType,
    lateral: Boolean = false
): Join {
    val fkKeys = findKeys(this, otherTable) ?: findKeys(otherTable, this) ?: emptyList()
    return when {
        joinType != JoinType.CROSS && fkKeys.isEmpty() -> {
            error(
                "Cannot join with $otherTable as there is no matching primary key/foreign key pair and constraint missing"
            )
        }

        fkKeys.any { it.second.size > 1 } -> {
            val references = fkKeys.joinToString(" & ") { "${it.first} -> ${it.second.joinToString()}" }
            error(
                "Cannot join with $otherTable as there is multiple primary key <-> foreign key references.\n$references"
            )
        }

        else -> {
            val cond = fkKeys.filter { it.second.size == 1 }.map { it.first to it.second.single() }
            join(otherTable, joinType, cond, additionalConstraint = null, lateral = lateral)
        }
    }
}

