when {
  p == PEEKED_LONG -> {
    peeked = PEEKED_NONE
    pathIndices[stackSize - 1]++
    return peekedLong
  }
  p == PEEKED_NUMBER -> {
    peekedString = buffer.readUtf8(peekedNumberLength.toLong())
  }
  p == PEEKED_DOUBLE_QUOTED || p == PEEKED_SINGLE_QUOTED -> {
    peekedString = if (p == PEEKED_DOUBLE_QUOTED) nextQuotedValue(DOUBLE_QUOTE_OR_SLASH) else nextQuotedValue(SINGLE_QUOTE_OR_SLASH)
    try {
      val result = peekedString!!.toLong()
      peeked = PEEKED_NONE
      pathIndices[stackSize - 1]++
      return result
    } catch (ignored: NumberFormatException) { // Fall back to parse as a double below.
    }
  }
  p != PEEKED_BUFFERED -> throw JsonDataException("Expected a long but was ${peek()} at path ${getPathAsString()}")
}

when {
  p == PEEKED_LONG -> {
    val result = peekedLong.toInt()
    if (peekedLong != result.toLong()) { // Make sure no precision was lost casting to 'int'.
      throw JsonDataException("Expected an int but was " + peekedLong
          + " at path " + getPath())
    }
    peeked = PEEKED_NONE
    pathIndices[stackSize - 1]++
    return result
  }
  p == PEEKED_NUMBER -> {
    peekedString = buffer.readUtf8(peekedNumberLength.toLong())
  }
  p == PEEKED_DOUBLE_QUOTED || p == PEEKED_SINGLE_QUOTED -> {
    peekedString = if (p == PEEKED_DOUBLE_QUOTED) nextQuotedValue(DOUBLE_QUOTE_OR_SLASH) else nextQuotedValue(SINGLE_QUOTE_OR_SLASH)
    try {
      val result = peekedString!!.toInt()
      peeked = PEEKED_NONE
      pathIndices[stackSize - 1]++
      return result
    } catch (ignored: NumberFormatException) { // Fall back to parse as a double below.
    }
  }
  p != PEEKED_BUFFERED -> {
    throw JsonDataException("Expected an int but was ${peek()} at path ${getPathAsString()}")
  }
}

when (it) {
  is GQLField -> {
    it.selections.detectCycles(globallyVisitedFragments, locallyVisitedFragments, path + it.responseName())
  }

  is GQLInlineFragment -> {
    it.selections.detectCycles(globallyVisitedFragments, locallyVisitedFragments, path + "__on${it.typeCondition?.name ?: ""}")
  }

  is GQLFragmentSpread -> {
    val fragment = fragmentDefinitions.get(it.name)
    if (fragment != null) {
      val name = fragment.name
      val index = path.indexOf("__${name}")
      val nextPath = path + "__${fragment.name}"
      if (index != -1) {
        issues.add(FragmentCycle("Fragment '$name' spreads itself, creating a cycle at '${nextPath.subList(index, nextPath.size).joinToString(".")}'", it.sourceLocation))
        cyclicFragments.add(name)
        return@forEach
      }

      fragment.detectCycles(globallyVisitedFragments, locallyVisitedFragments, nextPath)
    }
  }
}

