if (iterableTypeParameter != null) {
    val typeParameter = arrayType ?: iterableTypeParameter
    val iterableDeclaration = when {
        mapLikeParameters != null
            -> {
            val mapLikeType = when (name) {
                "URLSearchParams",
                "MediaKeyStatusMap",
                    -> "ReadonlyMap"

                else -> "MapLike"
            }

            val result = "$mapLikeType<${mapLikeParameters.key}, ${mapLikeParameters.value}>"
            if (name == "StylePropertyMapReadOnly") {
                "$result,\nReadonlySetLike<${mapLikeParameters.key}>"
            } else result
        }

        listLikeMode
            -> "ListLike<$typeParameter>"

        else -> "JsIterable<$typeParameter>"
    }

    declaration += if (":" in declaration && name != "NodeList" && name != "DOMTokenList") "," else ":"
    declaration += "\n$iterableDeclaration"
}

for (declaration in declarations.sortedBy(Declaration::name)) {
    for ((name, body) in declaration.toConversionResults()) {
        val file = sourceDir.resolve("${name}.kt")
        if (!file.exists()) {
            val isRuntime = hasRuntimeDeclarations(body)

            val content = sequenceOf(
                "// $GENERATOR_COMMENT",
                moduleDeclaration.takeIf { isRuntime } ?: "",
                "package $pkg",
                defaultImports,
                toCommonBody(body),
            ).filter { it.isNotEmpty() }
                .joinToString("\n\n")

            file.writeCode(content)
        } else {
            // for functions with union type parameters
            file.appendText("\n\n")
        }
    }
}

if (!staticBody) {
    val staticMembers = members.filter { it.static }
        .plus(companionMembers)

    val packable = name != PACKABLE
            && name != "PlaneOutlineGeometry" // WA
            && name != "BufferPrimitiveMaterial" // WA
            && staticMembers.any { it.name == PACKED_LENGTH }

    if (packable) {
        staticMembers.asSequence()
            .filter { it.name in PACKABLE_MEMBERS }
            .forEach { it.overridden = true }
    }

    val companionBody = staticMembers
        .map { it.toCode() }
        .joinToString(separator = "\n\n")

    val companionTypes = if (packable) {
        ": $PACKABLE<$name>"
    } else ""

    if (companionBody.isNotEmpty()) {
        body += "\n\ncompanion object $companionTypes {\n$companionBody\n}"
    }
}

when (propertyOverride) {
    is Overlap -> {
        val alias = propertyOverride.alias
        val jsName = "@JsName(\"$name\")"
        val aliasSignature = "${modifier}${alias}: $type"
        val deprecation = "@Deprecated(message = \"use ${alias}\", level = DeprecationLevel.HIDDEN)"
        val signature = "override ${modifier}${name}: ${propertyOverride.parentType}"

        arrayOf(
            deprecation,
            signature,
            jsName,
            aliasSignature,
        ).joinToString("\n")
    }
    is Alias -> {
        val alias = propertyOverride.alias
        val jsName = "@JsName(\"$name\")"
        val aliasSignature = "${modifier}${alias}: $type"

        arrayOf(
            jsName,
            aliasSignature,
        ).joinToString("\n")
    }
    Preserve -> "override ${modifier}${name}: $type"
}

while (true) {
    sb.append("${segment.hexAddress}=[${if (segment.isRemoved) "*" else ""}${segment.id},prev=${segment.prev?.hexAddress},")
    repeat(SEGMENT_SIZE) { i ->
        val cellState = segment.getState(i)
        val element = segment.getElement(i)
        val cellStateString = when (cellState) {
            is CancellableContinuation<*> -> "cont"
            is SelectInstance<*> -> "select"
            is ReceiveCatching<*> -> "receiveCatching"
            is SendBroadcast -> "send(broadcast)"
            is WaiterEB -> "EB($cellState)"
            else -> cellState.toString()
        }
        sb.append("[$i]=($cellStateString,$element),")
    }
    sb.append("next=${segment.next?.hexAddress}]  ")
    // Process the next segment if exists.
    segment = segment.next ?: break
}

try {
    call.attributes.put(StaticFileLocationProperty, resourcePath)
    val (location, info) = extractWebJar(resourcePath, knownWebJars, locator)
    val stream = WebjarsConfig::class.java.classLoader.getResourceAsStream(location) ?: return@onCall
    val content = InputStreamContent(stream, ContentType.defaultForFilePath(fullPath)).apply {
        lastModifiedExtractor(info)?.let { versions += LastModifiedVersion(it) }
        etagExtractor(info)?.let { versions += EntityTagVersion(it) }
        maxAgeExtractor(info)?.let { caching = CachingOptions(CacheControl.MaxAge(it.inWholeSeconds.toInt())) }
    }
    call.respond(content)
} catch (multipleFiles: MultipleMatchesException) {
    when (val message = multipleFiles.message) {
        null -> call.respond(HttpStatusCode.InternalServerError)
        else -> call.respond(HttpStatusCode.InternalServerError, message)
    }
} catch (_: IllegalArgumentException) {
}

when (this) {
  is AbstractFlatMap<A> -> object : FlatMap<B>() {
    override suspend fun <S> startSuspend(): SuspendEval<S> = (this@SuspendEval).startSuspend()

    // @IgnoreJRERequirement
    override suspend fun <S> runSuspend(s: S): SuspendEval<B> =
      object : FlatMap<B>() {
        override suspend fun <S1> startSuspend(): SuspendEval<S1> = (this@SuspendEval).runSuspend(s) as SuspendEval<S1>
        override suspend fun <S1> runSuspend(s1: S1): SuspendEval<B> = f(s1 as A)
      }
  }
  is AbstractDefer<A> -> object : FlatMap<B>() {
    override suspend fun <S> startSuspend(): SuspendEval<S> = this@SuspendEval.thunk() as SuspendEval<S>
    override suspend fun <S> runSuspend(s: S): SuspendEval<B> = f(s as A)
  }
  else -> object : FlatMap<B>() {
    override suspend fun <S> startSuspend(): Eval<S> = this@SuspendEval as Eval<S>
    override suspend fun <S> runSuspend(s: S): SuspendEval<B> = f(s as A)
  }
}

when (self) {
  is Single<*, *, *> -> {
    val f = self.f as ((Any?, Any?) -> Any?)
    if (joins == 0) f(currentA, currentB) as C
    else loop(f(currentA, currentB) as AndThen2<Any?, Any?, Any?>, null, null, joins - 1)
  }
  is Concat<*, *, *, *> -> {
    when (val oldLeft = self.left) {
      is Single<*, *, *> -> {
        val left = oldLeft as Single<Any?, Any?, Any?>
        val newSelf = self.right as AndThen1<Any?, Any?>
        AndThen1.loop(newSelf, left.f(currentA, currentB), joins)
      }
      is Concat<*, *, *, *> -> loop(
        rotateAccumulate(self.left as AndThen2<Any?, Any?, Any?>, self.right as AndThen1<Any?, Any?>),
        currentA,
        currentB,
        joins
      )
    }
  }
}

if (sourceLocation?.filePath != null && sourceLocation.line >= 1 && sourceLocation.column >= 1) {
  val filePath = sourceLocation.filePath
  val document = try {
    HOST_FILESYSTEM.source(filePath.toPath()).buffer().readUtf8()
  } catch (e: IOException) {
    throw RuntimeException("Failed to read GraphQL file `$this`", e)
  }
  val documentLines = document.lines()
  "\n----------------------------------------------------\n" +
      run {
        val prefix = if (sourceLocation.line - 2 >= 0) {
          "[${sourceLocation.line - 1}]:" + documentLines[sourceLocation.line - 2]
        } else ""
        val body = "\n[${sourceLocation.line}]:${documentLines[sourceLocation.line - 1]}\n"
        val postfix = if (sourceLocation.line < documentLines.size) {
          "[${sourceLocation.line + 1}]:" + documentLines[sourceLocation.line]
        } else ""
        "$prefix$body$postfix"
      } +
      "\n----------------------------------------------------"
} else {
  ""
}

when {
    source.startsWith("@example") -> source.removePrefix("@example\n").let { "```\n${cleanupCode(it)}\n```" }
    source.startsWith("@param ") -> when {
        hideParams -> null
        hideOptions && source.startsWith("@param options.") -> null
        hideOptions && source.startsWith("@param [options.") -> null
        source.endsWith("Object with the following properties:") -> null
        source.endsWith("An object with the following properties:") -> null
        source.endsWith("An object with the following properties.") -> null
        source.endsWith("Object describing initialization options") -> null
        else -> formatParam(source, "@param ")
    }

    source.startsWith("@property ") -> formatParam(source, "@property ")
    source.startsWith("@returns") -> source.replace("@returns", "@return").multiline()
    else -> source
}

